#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int numbers[n];
    for (int i = 0; i < n; ++i) {
        scanf("%d", &numbers[i]);
    }
    int index = -1;
    for (int i = 0; i < n; i++) {
        if (numbers[i] == 8) {
           index = i;       
           break;
        }
    }
    printf("%d", index);     
    return 0;
}
